import org.springframework.web.bind.annotation.*;
import org.springframework.http.*;
import java.util.*;

@RestController
@RequestMapping("/fallback")
public class GatewayFallbackController {

    // Non-critical: return empty list
    @GetMapping("/restaurants")
    public ResponseEntity<Map<String,Object>> restaurantsFallback() {
        return ResponseEntity.ok(Map.of(
            "restaurants", List.of(),
            "message", "Restaurant listings temporarily unavailable",
            "cached", false
        ));
    }

    // Important: return in-progress status
    @GetMapping("/orders")
    public ResponseEntity<Map<String,String>> ordersFallback() {
        return ResponseEntity
            .status(HttpStatus.SERVICE_UNAVAILABLE)
            .body(Map.of(
                "status",  "CHECKING",
                "message", "Order service temporarily unavailable — your order is being processed",
                "retry",   "true"
            ));
    }

    // Critical: explicit error — don't silently degrade payments
    @GetMapping("/payments")
    public ResponseEntity<Map<String,String>> paymentsFallback() {
        return ResponseEntity
            .status(HttpStatus.SERVICE_UNAVAILABLE)
            .body(Map.of(
                "error",   "Payment service temporarily unavailable",
                "message", "Please retry in a few minutes",
                "code",    "PAYMENT_SERVICE_UNAVAILABLE"
            ));
    }
}

import org.springframework.cloud.gateway.filter.ratelimit.KeyResolver;
import org.springframework.context.annotation.*;
import reactor.core.publisher.Mono;
import java.util.List;

@Configuration
public class GatewayKeyResolvers {

    // Rate limit by API key header:
    @Bean("apiKeyResolver")
    public KeyResolver apiKeyResolver() {
        return exchange -> {
            String apiKey = exchange.getRequest()
                .getHeaders().getFirst("X-API-Key");
            return Mono.just(apiKey != null ? apiKey : "anonymous");
        };
    }

    // Rate limit by remote IP:
    @Bean("ipResolver")
    public KeyResolver ipResolver() {
        return exchange -> {
            var addr = exchange.getRequest().getRemoteAddress();
            return Mono.just(addr != null ? addr.getAddress().getHostAddress() : "unknown");
        };
    }

    // Usage in application.yml:
    // filters:
    //   - name: RequestRateLimiter
    //     args:
    //       key-resolver: '#{@apiKeyResolver}'   # Bean reference with SpEL
    //       redis-rate-limiter.replenishRate: 100
    //       redis-rate-limiter.burstCapacity: 150
    //
    //   - name: RequestRateLimiter
    //     args:
    //       key-resolver: '#{@ipResolver}'       # Different resolver for different route
    //       redis-rate-limiter.replenishRate: 20
