import org.springframework.cloud.gateway.route.RouteDefinition;
import org.springframework.cloud.gateway.route.RouteDefinitionRepository;
import org.springframework.cloud.gateway.event.RefreshRoutesEvent;
import org.springframework.context.ApplicationEventPublisher;
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import reactor.core.publisher.Mono;
import java.net.URI;

@RestController
@RequestMapping("/admin/gateway")
public class GatewayAdminController {
    private final RouteDefinitionRepository routeRepo;
    private final ApplicationEventPublisher publisher;

    GatewayAdminController(RouteDefinitionRepository r, ApplicationEventPublisher p) {
        routeRepo=r; publisher=p;
    }

    // Add a route dynamically:
    @PostMapping("/routes")
    public ResponseEntity<String> addRoute(@RequestBody RouteDefinition definition) {
        routeRepo.save(Mono.just(definition)).subscribe();
        publisher.publishEvent(new RefreshRoutesEvent(this));  // apply changes
        return ResponseEntity.ok("Route '" + definition.getId() + "' added");
    }

    // Remove a route:
    @DeleteMapping("/routes/{id}")
    public ResponseEntity<String> removeRoute(@PathVariable String id) {
        routeRepo.delete(Mono.just(id)).subscribe();
        publisher.publishEvent(new RefreshRoutesEvent(this));
        return ResponseEntity.ok("Route '" + id + "' removed");
    }

    // Use case: feature flags — enable new service route without restart
    // Use case: blue-green deployment — switch route from v1 to v2 dynamically
    // Use case: A/B testing — add experimental route for 10% of traffic

    public static void main(String[] a) {
        System.out.println("Dynamic route management: add/remove without restart");
    }
}

