# application.yml:
# spring:
#   cloud:
#     gateway:
#       discovery:
#         locator:
#           enabled: true          # auto-create routes for registered services
#           lowerCaseServiceId: true
#     loadbalancer:
#       ribbon:
#         enabled: false           # use Spring Cloud LoadBalancer (not Ribbon)
#   application:
#     name: api-gateway
#
# eureka:
#   client:
#     serviceUrl:
#       defaultZone: http://eureka-server:8761/eureka/
#
# Route with lb://:
# - id: payment-service
#   uri: lb://payment-service      # lb:// = Spring Cloud LoadBalancer
#   predicates: [Path=/api/payments/**]
#   # LoadBalancer picks a healthy instance from Eureka registry
#   # If instance goes down: Eureka deregisters it → LB stops sending traffic

import org.springframework.cloud.client.loadbalancer.LoadBalanced;
import org.springframework.context.annotation.*;
import org.springframework.web.reactive.function.client.WebClient;

@Configuration
public class GatewayLoadBalancerConfig {

    @Bean @LoadBalanced
    public WebClient.Builder loadBalancedWebClient() {
        return WebClient.builder();
        // Used by gateway internally for lb:// URI resolution
    }

    // HOW CIRCUIT BREAKER + LOAD BALANCER INTERACT:
    // Request → Gateway → LoadBalancer (picks instance-1)
    // instance-1 fails → CB records failure
    // Next request → LoadBalancer (picks instance-2)
    // instance-1 keeps getting picked → CB failure rate rises → CB OPENS
    // CB OPEN: all requests → fallback (no calls to ANY instance of payment-service)

    // Healthier: pair with Eureka health check
    // Instance-1 unhealthy → Eureka deregisters → LB never picks it
    // CB sees only healthy instances → CB opens less often

    public static void main(String[] a) {
        System.out.println("lb://service-name: LoadBalancer picks healthy registered instance");
        System.out.println("CB + LB: circuit opens if ALL instances of a service are failing");
    }
}

