// Gateway fallback controller:
@RestController @RequestMapping("/fallback")
class M19FallbackCtrl{
    @GetMapping("/payment") public ResponseEntity<?> payment(){
        return ResponseEntity.status(503).body(Map.of("error","Payment unavailable"));}
