// Payment service (inner layers):
@Service
class M19PaymentService{
    interface GatewayClient{String process(String id);}
    private final GatewayClient c;
    M19PaymentService(GatewayClient g){c=g;}
    @Bulkhead(name="m19",fallbackMethod="bhFb")
    @CircuitBreaker(name="m19",fallbackMethod="cbFb")
    @Retry(name="m19")
    @TimeLimiter(name="m19",fallbackMethod="tlFb")
    public CompletableFuture<String> process(String id){return CompletableFuture.supplyAsync(()->c.process(id));}
    private CompletableFuture<String> bhFb(String id,BulkheadFullException e){return CompletableFuture.completedFuture("BULKHEAD");}
    private CompletableFuture<String> cbFb(String id,Exception e){return CompletableFuture.completedFuture("CB_OPEN");}
    private CompletableFuture<String> tlFb(String id,Exception e){return CompletableFuture.completedFuture("TIMEOUT");}
}

// CB alert listener:
@Service
class M19AlertService{
    public final AtomicInteger cbOpened=new AtomicInteger(0);
    private final CircuitBreakerRegistry reg;
    M19AlertService(CircuitBreakerRegistry r){reg=r;}
    @PostConstruct void listen(){
        reg.getAllCircuitBreakers().forEach(cb->cb.getEventPublisher()
            .onStateTransition(e->{
                if(e.getStateTransition()==CircuitBreaker.StateTransition.CLOSED_TO_OPEN){
                    cbOpened.incrementAndGet();
                    System.err.println("[ALERT] "+cb.getName()+" circuit OPENED");
                }
            }));
    }
}

@SpringBootTest(webEnvironment=SpringBootTest.WebEnvironment.RANDOM_PORT)
class M19SynthesisTest{
    @Autowired WebTestClient wc;
    @Autowired M19PaymentService svc;
    @Autowired M19AlertService alertSvc;
    @MockBean M19PaymentService.GatewayClient client;
    @Autowired CircuitBreakerRegistry reg;
    @BeforeEach void reset(){try{reg.circuitBreaker("m19").reset();}catch(Exception ignore){} alertSvc.cbOpened.set(0);}
    @Test void gatewayFallback_returns503(){wc.get().uri("/fallback/payment").exchange().expectStatus().isEqualTo(503);}
    @Test void serviceLevel_fallback() throws Exception{
        when(client.process(any())).thenThrow(new RuntimeException("down"));
        String r=svc.process("P001").get();
        assertNotNull(r);assertTrue(r.equals("CB_OPEN")||r.equals("BULKHEAD")||r.equals("TIMEOUT"));
    }
    @Test void cbAlertFired_afterFailures() throws Exception{
        when(client.process(any())).thenThrow(new RuntimeException("down"));
        for(int i=0;i<10;i++) try{svc.process("P-"+i).get();}catch(Exception ignore){}
        assertTrue(reg.circuitBreaker("m19").getState()==CircuitBreaker.State.OPEN||alertSvc.cbOpened.get()>0);
    }
}
